import { ChangeDetectorRef, inject } from '@angular/core';

export class LiveDataComponent {
  private cdr = inject(ChangeDetectorRef);

  onWebSocketMessage(data: any) {
    this.items = data.items;
    this.cdr.markForCheck(); // schedules this component and ancestors for next CD cycle
  }
}

import { HttpClient, HttpErrorResponse } from '@angular/common/http';
import { catchError, throwError } from 'rxjs';

@Injectable({ providedIn: 'root' })
export class ProductService {
  constructor(private http: HttpClient) {}

  getProducts() {
    return this.http.get<Product[]>('/api/products').pipe(
      catchError((err: HttpErrorResponse) => {
        console.error('Status:', err.status);
        console.error('URL:', err.url);
        console.error('Body:', err.error);
        return throwError(() => err);
      })
    );
  }
}

import { HttpInterceptorFn } from '@angular/common/http';
import { tap } from 'rxjs';

export const loggingInterceptor: HttpInterceptorFn = (req, next) => {
  console.log(`▶ ${req.method} ${req.url}`);
  return next(req).pipe(
    tap({
      next: response => console.log(`◀ ${response.status}`, response),
      error: err => console.error(`✖ ${err.status} ${req.url}`, err),
    })
  );
};

